const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

app.use(express.json());

const PORT = process.env.PORT || 3000;
const SESSION_TTL_MS = 1000 * 60 * 60 * 24 * 7;

const users = new Map();
const sessions = new Map();
const playersBySocket = new Map();
const leaderboard = new Map();

function hashPassword(password, salt) {
  return crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
}

function createUser(username, password) {
  if (users.has(username)) return false;
  const salt = crypto.randomBytes(16).toString('hex');
  const passwordHash = hashPassword(password, salt);
  users.set(username, {
    username,
    salt,
    passwordHash,
    createdAt: Date.now()
  });
  leaderboard.set(username, leaderboard.get(username) || 0);
  return true;
}

function verifyUser(username, password) {
  const user = users.get(username);
  if (!user) return false;
  const passwordHash = hashPassword(password, user.salt);
  return crypto.timingSafeEqual(
    Buffer.from(passwordHash, 'hex'),
    Buffer.from(user.passwordHash, 'hex')
  );
}

function createSession(username) {
  const token = crypto.randomBytes(32).toString('hex');
  sessions.set(token, {
    username,
    createdAt: Date.now(),
    expiresAt: Date.now() + SESSION_TTL_MS
  });
  return token;
}

function getSession(token) {
  const session = sessions.get(token);
  if (!session) return null;
  if (session.expiresAt < Date.now()) {
    sessions.delete(token);
    return null;
  }
  return session;
}

function destroySession(token) {
  sessions.delete(token);
}

function sanitizeUsername(username) {
  if (typeof username !== 'string') return null;
  const trimmed = username.trim();
  if (!/^[a-zA-Z0-9_]{3,20}$/.test(trimmed)) return null;
  return trimmed;
}

function getTopLeaderboard(limit = 20) {
  return [...leaderboard.entries()]
    .map(([username, score]) => ({ username, score }))
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);
}

setInterval(() => {
  const now = Date.now();
  for (const [token, session] of sessions.entries()) {
    if (session.expiresAt < now) {
      sessions.delete(token);
    }
  }
}, 60 * 1000);

app.post('/register', (req, res) => {
  const username = sanitizeUsername(req.body.username);
  const password = typeof req.body.password === 'string' ? req.body.password : '';

  if (!username || password.length < 6) {
    return res.status(400).json({ error: 'Invalid username or password' });
  }

  if (!createUser(username, password)) {
    return res.status(409).json({ error: 'Username already exists' });
  }

  const token = createSession(username);
  res.json({ success: true, token, username });
});

app.post('/login', (req, res) => {
  const username = sanitizeUsername(req.body.username);
  const password = typeof req.body.password === 'string' ? req.body.password : '';

  if (!username || !password) {
    return res.status(400).json({ error: 'Invalid credentials' });
  }

  if (!verifyUser(username, password)) {
    return res.status(401).json({ error: 'Authentication failed' });
  }

  const token = createSession(username);
  res.json({ success: true, token, username });
});

app.post('/logout', (req, res) => {
  const auth = req.headers.authorization || '';
  const token = auth.startsWith('Bearer ') ? auth.slice(7) : null;

  if (token) destroySession(token);
  res.json({ success: true });
});

app.get('/leaderboard', (req, res) => {
  res.json({ leaderboard: getTopLeaderboard() });
});

io.use((socket, next) => {
  const token = socket.handshake.auth?.token || socket.handshake.headers['x-session-token'];
  if (!token) return next(new Error('Unauthorized'));

  const session = getSession(token);
  if (!session) return next(new Error('Invalid session'));

  socket.sessionToken = token;
  socket.username = session.username;
  next();
});

io.on('connection', (socket) => {
  playersBySocket.set(socket.id, {
    username: socket.username,
    score: leaderboard.get(socket.username) || 0,
    x: 0,
    y: 0,
    connectedAt: Date.now()
  });

  socket.emit('authenticated', {
    username: socket.username,
    score: leaderboard.get(socket.username) || 0,
    leaderboard: getTopLeaderboard()
  });

  socket.broadcast.emit('playerJoined', {
    username: socket.username
  });

  socket.on('submitScore', (payload = {}) => {
    const score = Number(payload.score);

    if (!Number.isFinite(score) || score < 0) {
      return socket.emit('errorMessage', { error: 'Invalid score' });
    }

    leaderboard.set(socket.username, score);

    const player = playersBySocket.get(socket.id);
    if (player) {
      player.score = score;
    }

    io.emit('leaderboardUpdated', {
      leaderboard: getTopLeaderboard()
    });
  });

  socket.on('playerMove', (payload = {}) => {
    const x = Number(payload.x);
    const y = Number(payload.y);

    if (!Number.isFinite(x) || !Number.isFinite(y)) {
      return socket.emit('errorMessage', { error: 'Invalid move payload' });
    }

    const player = playersBySocket.get(socket.id);
    if (player) {
      player.x = x;
      player.y = y;
    }

    socket.broadcast.emit('playerMoved', {
      username: socket.username,
      x,
      y
    });
  });

  socket.on('getLeaderboard', () => {
    socket.emit('leaderboardUpdated', {
      leaderboard: getTopLeaderboard()
    });
  });

  socket.on('disconnect', () => {
    playersBySocket.delete(socket.id);
    socket.broadcast.emit('playerLeft', {
      username: socket.username
    });
  });
});

server.listen(PORT, () => {
  console.log(`Server listening on port ${PORT}`);
});